import json
import re

business_data = var_functions.query_db:22
rating_data = var_functions.query_db:26

# Extract state information from business descriptions
business_state_map = {}
for business in business_data:
    business_id = business['business_id']
    business_ref = business_id.replace('businessid_', 'businessref_')
    desc = business.get('description', '')

    if desc:
        state_match = re.search(r'\b([A-Z]{2})\b', desc)
        if state_match:
            state = state_match.group(1)
            business_state_map[business_ref] = state

print("State mapping created for %d businesses" % len(business_state_map))

# Calculate total reviews per state from business metadata
state_reviews = {}
for business in business_data:
    desc = business.get('description', '')
    if desc:
        state_match = re.search(r'\b([A-Z]{2})\b', desc)
        if state_match:
            state = state_match.group(1)
            review_count = int(business['review_count'])
            state_reviews[state] = state_reviews.get(state, 0) + review_count

# Find state with highest number of reviews
sorted_states = sorted(state_reviews.items(), key=lambda x: x[1], reverse=True)
print("States by review count (top 5):", sorted_states[:5])

# Calculate average rating per state
state_ratings = {}
for rating in rating_data:
    business_ref = rating['business_ref']
    state = business_state_map.get(business_ref)
    if state:
        avg_rating = float(rating['avg_rating'])
        if state not in state_ratings:
            state_ratings[state] = []
        state_ratings[state].append(avg_rating)

# Average ratings per state
state_avg_ratings = {}
for state, ratings in state_ratings.items():
    state_avg_ratings[state] = sum(ratings) / len(ratings)

# Match top state from review counts with its average rating
if sorted_states:
    top_state, top_review_count = sorted_states[0]
    top_state_avg_rating = state_avg_ratings.get(top_state, 0)

    result = {
        "state": top_state,
        "total_reviews": top_review_count,
        "avg_rating": round(top_state_avg_rating, 2)
    }
else:
    result = {"error": "No state data found"}

print("__RESULT__:")
print(json.dumps(result))

